export default function createSpy(impl) {
  function spy(...args) {
    spy.calls.push(args);
    spy.thisValues.push(this);
    if (typeof impl === 'function') {
      return impl.apply(this, args);
    }
    return undefined;
  }

  spy.calls = [];
  spy.thisValues = [];
  spy.callCount = () => spy.calls.length;
  spy.lastCall = () => (spy.calls.length ? spy.calls[spy.calls.length - 1] : null);
  spy.reset = () => {
    spy.calls.length = 0;
    spy.thisValues.length = 0;
  };

  return spy;
}
